import json
import re

key = 'var_function-call-6572188807107895233'
data_source = locals()[key]

if isinstance(data_source, str):
    with open(data_source, 'r') as f:
        businesses = json.load(f)
else:
    businesses = data_source

us_states = {'AL', 'AK', 'AZ', 'AR', 'CA', 'CO', 'CT', 'DE', 'FL', 'GA', 'HI', 'ID', 'IL', 'IN', 'IA', 'KS', 'KY', 'LA', 'ME', 'MD', 'MA', 'MI', 'MN', 'MS', 'MO', 'MT', 'NE', 'NV', 'NH', 'NJ', 'NM', 'NY', 'NC', 'ND', 'OH', 'OK', 'OR', 'PA', 'RI', 'SC', 'SD', 'TN', 'TX', 'UT', 'VT', 'VA', 'WA', 'WV', 'WI', 'WY', 'DC'}

state_counts = {}
top_state_businesses = []

for b in businesses:
    attrs = b.get('attributes')
    if not attrs or not isinstance(attrs, dict):
        continue

    wifi = str(attrs.get('WiFi', '')).lower()
    has_wifi = ('free' in wifi or 'paid' in wifi) and ('no' not in wifi)

    # Fallback for strict strings
    if not has_wifi:
        if "u'free'" in wifi or "u'paid'" in wifi:
            has_wifi = True

    if has_wifi:
        desc = b.get('description', '')
        # Simple extraction
        parts = desc.split(',')
        # Look for state code in parts
        found_state = None
        for part in parts:
            clean = part.strip().split(' ')[0] # take first word if multiple
            if len(clean) == 2 and clean.upper() in us_states:
                found_state = clean.upper()
                break

        # Regex backup if simple split fails
        if not found_state:
            match = re.search(r',\s([A-Z]{2})(?:,|\s)', desc)
            if match and match.group(1) in us_states:
                found_state = match.group(1)

        if found_state:
            state_counts[found_state] = state_counts.get(found_state, 0) + 1
            if found_state == 'PA': # Just a placeholder, will find top later
                pass

# Find top state
top_state = max(state_counts, key=state_counts.get) if state_counts else None
max_count = state_counts[top_state] if top_state else 0

# Collect IDs for top state
ids = []
if top_state:
    for b in businesses:
        attrs = b.get('attributes')
        if not attrs or not isinstance(attrs, dict): continue
        wifi = str(attrs.get('WiFi', '')).lower()
        has_wifi = ('free' in wifi or 'paid' in wifi) and ('no' not in wifi)
        if not has_wifi:
             if "u'free'" in wifi or "u'paid'" in wifi: has_wifi = True

        if has_wifi:
            desc = b.get('description', '')
            match = re.search(r',\s([A-Z]{2})(?:,|\s)', desc)
            if match and match.group(1) == top_state:
                ids.append(b['business_id'].replace('businessid_', 'businessref_'))

print("__RESULT__:")
print(json.dumps({
    "top_state": top_state,
    "count": max_count,
    "ids": ids
}))

